+    bootstrapFiles,
+    injectedFiles: contextFiles,
+    skillsPrompt: "",
+    tools: [],
+  });
+
+  return {
+    params,
+    started,
+    workspaceDir,
+    backendResolved,
+    preparedBackend,
+    reusableCliSession,
+    modelId,
+    normalizedModel,
+    systemPrompt,
+    systemPromptReport,
+    bootstrapPromptWarningLines: bootstrapPromptWarning.lines,
+    heartbeatPrompt,
